// Pattern:
// If a Postgres node precedes a binary consumer,
// restore binary from the trigger using node reference.
//
// Here: 'Load OCR Provider Settings' (Postgres) sits between the trigger and the Azure
// node. Postgres replaces the item and drops item.binary, so the Azure node would not see
// the file. We restore it from the trigger by node reference (verified working: the boundary
// probe resolved $('When Executed by WF-001').first().binary and getBinaryDataBuffer read the
// full file). json (the loaded OCR settings) passes through unchanged.
return [{ json: $json, binary: $('When Executed by WF-001').first().binary }];

// SUBMIT ADAPTER (provider-independent shell; Azure defaults).
// Extracts the poll URL from the submit response using provider config, and initialises poll state.
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const poll = cfg.poll || {};
const HDR  = (poll.pollUrlHeader   || 'operation-location').toLowerCase();
const IVAL = Number(poll.pollIntervalMs ?? 2000);   // Azure: no faster than ~2s
const MAXA = Number(poll.maxAttempts    ?? 90);     // budget: 90 attempts
const MAXMS= Number(poll.maxElapsedMs   ?? 900000); // budget: 15 min hard ceiling

const res = $json;                       // fullResponse: { statusCode, headers, body }
const headers = res.headers || {};
// header lookup is case-insensitive
let pollUrl = null;
for (const k of Object.keys(headers)) { if (k.toLowerCase() === HDR) { pollUrl = headers[k]; break; } }
const status = res.statusCode;

if (status !== 202 || !pollUrl) {
  // Submit itself failed -> terminal failure, no polling.
  return [{ json: {
    _poll: { terminal: true, status: 'failed', attempt: 0, startedAt: Date.now(),
             intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS,
             error: `submit failed: HTTP ${status}` + (pollUrl ? '' : ' (no poll URL header)') },
    _result: null
  }}];
}
// Honor Retry-After from the submit response if present.
let firstWaitMs = IVAL;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) firstWaitMs = Math.max(IVAL, Number(ra) * 1000);

return [{ json: {
  _poll: { pollUrl, terminal: false, status: 'notStarted', attempt: 0, startedAt: Date.now(),
           waitMs: firstWaitMs, intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS, error: null },
  _result: null
}}];

// POLL ADAPTER (provider-independent shell; Azure defaults).
// Normalises the provider response to { status, result } and enforces the timeout budget.
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const pc   = cfg.poll || {};
const STATUS_PATH = pc.statusPath      || 'status';
const SUCCESS     = pc.terminalSuccess || 'succeeded';
const FAILURE     = pc.terminalFailure || 'failed';
const RESULT_PATH = pc.resultPath      || 'analyzeResult';

// carry poll state forward (the previous item is the one that entered the Wait)
const prev = $('submit() — capture pollUrl').first().json._poll;
let state = { ...prev, ...($json._poll || {}) };
// after the first loop the state rides on the item; recover it if the HTTP node replaced the item
if (!state.pollUrl) state = { ...prev };

const res  = $json;                       // fullResponse
const body = res.body || {};
const headers = res.headers || {};
const httpStatus = res.statusCode;

state.attempt = (Number(state.attempt) || 0) + 1;
const elapsed = Date.now() - Number(state.startedAt);

// read provider status via configured path
const opStatus = String(STATUS_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? '').toLowerCase();
const isSuccess = opStatus === String(SUCCESS).toLowerCase();
const isFailure = opStatus === String(FAILURE).toLowerCase();

// budget exhaustion -> terminal timeout
const overAttempts = state.attempt >= Number(state.maxAttempts);
const overElapsed  = elapsed      >= Number(state.maxElapsedMs);

let result = null, terminal = false, status = opStatus || 'running', error = null;
if (isSuccess) {
  terminal = true; status = 'succeeded';
  result = RESULT_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? body;
} else if (isFailure) {
  terminal = true; status = 'failed';
  error = JSON.stringify(body.error || body).slice(0, 500);
} else if (httpStatus >= 400) {
  terminal = true; status = 'failed';
  error = `poll HTTP ${httpStatus}: ` + JSON.stringify(body).slice(0, 300);
} else if (overAttempts || overElapsed) {
  terminal = true; status = 'timeout';
  error = `OCR poll budget exhausted after ${state.attempt} attempts / ${Math.round(elapsed/1000)}s`;
}

// next wait: honor Retry-After, else configured interval
let waitMs = Number(state.intervalMs) || 2000;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) waitMs = Math.max(waitMs, Number(ra) * 1000);
if (httpStatus === 429) waitMs = Math.max(waitMs * 2, 5000);   // backoff on throttle
state.waitMs = waitMs;
state.terminal = terminal; state.status = status; state.error = error;
state.httpStatus = httpStatus;
console.log('[SW-005 poll] attempt=' + state.attempt + ' http=' + httpStatus
  + ' status=' + status + ' terminal=' + terminal
  + ' pages=' + ((result && result.pages) ? result.pages.length : 'n/a'));

return [{ json: { _poll: state, _result: result } }];

// ===== INSTRUMENTATION ONLY — does not throw. Replaces shapeResult temporarily. =====
// Reports EVERY poll iteration across EVERY run index, and contrasts the two access methods.
const NODE = 'poll() — evaluate';

let maxRun = 0;
try { maxRun = $(NODE).runIndex || 0; } catch (e) {}

// (A) what the BROKEN code saw: .all() with default runIndex (single run)
let defaultAll = [];
try { defaultAll = ($(NODE).all() || []).map(i => i.json); } catch (e) {}

// (B) what the FIX sees: every run index walked
const every = [];
for (let r = 0; r <= maxRun; r++) {
  let items = [];
  try { items = $(NODE).all(0, r) || []; } catch (e) {}
  for (const it of items) if (it && it.json) every.push({ runIndex: r, json: it.json });
}

const table = every.map((e, i) => {
  const p = e.json._poll || {};
  const r = e.json._result;
  return {
    runIndex:   e.runIndex,
    attempt:    p.attempt ?? null,
    httpStatus: p.httpStatus ?? null,
    ocrStatus:  p.status ?? null,
    terminal:   p.terminal ?? null,
    resultPagesExists: !!(r && r.pages),
    resultPagesLength: (r && r.pages) ? r.pages.length : null,
    error:      p.error ?? null,
  };
});

const terms = every.map(e => e.json).filter(j => j._poll && j._poll.terminal === true);
const diag = {
  pollNodeRunIndex: maxRun,
  iterationsVisibleViaDefaultAll: defaultAll.length,
  iterationsVisibleWalkingAllRuns: every.length,
  iterations: table,
  terminalIterationsFound: terms.length,
  selected: terms.length ? {
    status: terms[terms.length-1]._poll.status,
    pages: (terms[terms.length-1]._result && terms[terms.length-1]._result.pages)
      ? terms[terms.length-1]._result.pages.length : null
  } : null,
};
console.log('[SW-005 PROBE] ' + JSON.stringify(diag, null, 2));
return [{ json: { _probe: diag } }];

// Select the TERMINAL poll iteration.
// n8n semantics: each pass of the Wait-loop is a separate RUN of 'poll() — evaluate'.
// $('poll() — evaluate').all() returns items of ONE run only (runIndex defaults to 0) — that is
// why a stale 'running' iteration (with _result=null) was being picked. We must walk EVERY run.
function allPollRuns() {
  const out = [];
  let maxRun = 0;
  try { maxRun = $('poll() — evaluate').runIndex || 0; } catch (e) { maxRun = 0; }
  for (let r = 0; r <= maxRun; r++) {
    let items = [];
    try { items = $('poll() — evaluate').all(0, r) || []; } catch (e) { items = []; }
    for (const it of items) if (it && it.json) out.push(it.json);
  }
  return out;
}
function terminalPoll() {
  const runs = allPollRuns();
  const term = runs.filter(j => j && j._poll && j._poll.terminal === true);
  if (term.length) return term[term.length - 1];
  // Failure path: tolerate absence; report what we saw.
  return runs.length ? runs[runs.length - 1] : {};
}
// Terminal failure/timeout -> ocr=null so WF-001's node-if-ocr routes to the §154 HUMAN_REVIEW path.
const incoming = $('When Executed by WF-001').first().json;
const final = terminalPoll();
const p = final._poll || {};
return [{ json: { ...incoming, ocr: null,
  ocrError: { status: p.status || 'failed', attempts: p.attempt || 0,
              message: p.error || 'OCR failed' } } }];
